mapper.update:
UPDATE abnormality_deal
processor = #{processor}, process_method = #{processMethod}, process_date = #{processDate}, review_date = #{reviewDate}, abnormal_occurred_date = #{abnormalOccurredDate}, process_opinion = #{processOpinion}, updated_at = #{updatedAt},
WHERE abnormality_id = #{abnormalityId}

mapper.select:
SELECT a.id, a.abnormal_code AS abnormalCode, a.device_unit_code AS deviceUnitCode, NULL AS partName, a.source, a.abnormal_location AS abnormalLocation, a.abnormal_type AS abnormalType, a.safety_output AS safetyOutput, a.reporter, a.abnormal_description AS abnormalDescription, a.report_date AS reportDate, a.status, a.creator_username AS creatorUsername, a.creator_name AS creatorName, a.created_at AS createdAt, a.updated_at AS updatedAt, d.processor AS handler, d.process_method AS processMethod, d.process_date AS handlerDate, d.review_date AS reviewDate, d.abnormal_occurred_date AS abnormalOccurredDate, d.process_opinion AS processOpinion FROM abnormality_record a LEFT JOIN abnormality_deal d ON d.abnormality_id = a.id
AND a.creator_username = #{creatorUsername}
AND a.abnormal_code LIKE CONCAT('%', #{abnormalCode}, '%')
AND a.device_unit_code LIKE CONCAT('%', #{deviceUnitCode}, '%')
AND a.reporter LIKE CONCAT('%', #{reporter}, '%')
AND a.report_date = #{reportDate}
AND a.status = #{status}
AND a.abnormal_type = #{abnormalType}
ORDER BY a.id DESC

SELECT a.id, a.abnormal_code AS abnormalCode, a.device_unit_code AS deviceUnitCode, NULL AS partName, a.source, a.abnormal_location AS abnormalLocation, a.abnormal_type AS abnormalType, a.safety_output AS safetyOutput, a.reporter, a.abnormal_description AS abnormalDescription, a.report_date AS reportDate, a.status, a.creator_username AS creatorUsername, a.creator_name AS creatorName, a.created_at AS createdAt, a.updated_at AS updatedAt, d.processor AS handler, d.process_method AS processMethod, d.process_date AS handlerDate, d.review_date AS reviewDate, d.abnormal_occurred_date AS abnormalOccurredDate, d.process_opinion AS processOpinion FROM abnormality_record a LEFT JOIN abnormality_deal d ON d.abnormality_id = a.id
AND a.status IN ('20', '30')
AND a.creator_username = #{creatorUsername}
AND a.abnormal_code LIKE CONCAT('%', #{abnormalCode}, '%')
AND a.device_unit_code LIKE CONCAT('%', #{deviceUnitCode}, '%')
AND a.reporter LIKE CONCAT('%', #{reporter}, '%')
AND a.report_date = #{reportDate}
AND a.status = #{status}
AND a.abnormal_type = #{abnormalType}
ORDER BY a.id DESC
